// Build lookup caches from preceding HTTP nodes
const cursorData = $('Get Sync Cursor').all().map(i => i.json).flat();
const channels = $('Get Channels').all().map(i => i.json).flat();
const warehouses = $('Get Warehouses').all().map(i => i.json).flat();
const variants = $('Get Variants').all().map(i => i.json).flat();

const channelCache = {};
for (const c of (Array.isArray(channels) ? channels : [channels])) {
  if (c && c.external_id) channelCache[String(c.external_id)] = c.id;
}

const warehouseCache = {};
for (const w of (Array.isArray(warehouses) ? warehouses : [warehouses])) {
  if (w && w.external_id) warehouseCache[String(w.external_id)] = w.id;
}

const variantCache = {};
const costPriceCache = {};
for (const v of (Array.isArray(variants) ? variants : [variants])) {
  if (v && v.sku) {
    variantCache[v.sku] = v.id;
    if (v.cost_price > 0) costPriceCache[v.sku] = +v.cost_price;
  }
}

const cursor = Array.isArray(cursorData) ? cursorData[0] : cursorData;
const sinceDate = cursor?.cursor_value || null;
const cursorId = cursor?.id || null;

return [{
  json: {
    sinceDate,
    cursorId,
    channelCache,
    warehouseCache,
    variantCache,
    costPriceCache,
    cacheStats: {
      channels: Object.keys(channelCache).length,
      warehouses: Object.keys(warehouseCache).length,
      variants: Object.keys(variantCache).length
    }
  }
}];

// Transform a single Veeqo order into all entity payloads
const order = $input.item.json;
const config = $('Build Config').first().json;

// ─── Status mapping ───
const statusMap = {
  awaiting_payment: 'awaiting_payment',
  awaiting_fulfillment: 'awaiting_fulfillment',
  partially_fulfilled: 'partially_shipped',
  shipped: 'shipped',
  delivered: 'delivered',
  cancelled: 'cancelled',
  on_hold: 'on_hold',
  refunded: 'refunded'
};
const orderStatus = statusMap[order.status] || 'pending';

// ─── Customer ───
const cust = order.customer;
const deliverTo = order.deliver_to;
const email = cust?.email || deliverTo?.email || null;
const firstName = cust?.full_name?.split(' ')[0] || deliverTo?.first_name || null;
const lastName = cust?.full_name?.split(' ').slice(1).join(' ') || deliverTo?.last_name || null;
const phone = cust?.phone || cust?.mobile || deliverTo?.phone || null;

const customer = (email || firstName) ? {
  first_name: firstName,
  last_name: lastName,
  email,
  phone,
  customer_type: cust?.customer_type || 'retail',
  channel_customer_ids: { veeqo: String(cust?.id || '') }
} : null;

// ─── Addresses ───
const shippingAddress = deliverTo?.address1 ? {
  address_type: 'shipping',
  first_name: deliverTo.first_name || null,
  last_name: deliverTo.last_name || null,
  company: deliverTo.company || null,
  address_line_1: deliverTo.address1,
  address_line_2: deliverTo.address2 || null,
  city: deliverTo.city || deliverTo.city_locality || '',
  state: deliverTo.state || deliverTo.state_province || null,
  country: deliverTo.country || deliverTo.country_code || 'US',
  postal_code: deliverTo.zip || deliverTo.postal_code || '',
  phone: deliverTo.phone || null,
  email: deliverTo.email || null,
  is_verified: deliverTo.verified || false,
  is_residential: deliverTo.residential !== false
} : null;

const ba = order.billing_address;
const billingAddress = ba?.address1 ? {
  address_type: 'billing',
  first_name: ba.first_name || null,
  last_name: ba.last_name || null,
  company: ba.company || null,
  address_line_1: ba.address1,
  address_line_2: ba.address2 || null,
  city: ba.city || ba.city_locality || '',
  state: ba.state || ba.state_province || null,
  country: ba.country || ba.country_code || 'US',
  postal_code: ba.zip || ba.postal_code || '',
  phone: ba.phone || null,
  email: ba.email || null
} : null;

// ─── Resolve cache lookups ───
const channelId = config.channelCache[String(order.channel?.id)] || null;
const warehouseId = config.warehouseCache[String(order.allocations?.[0]?.warehouse?.id)] || null;

// ─── Order record (IDs filled in later) ───
const orderRecord = {
  order_number: order.number || String(order.id),
  channel_id: channelId,
  status: orderStatus,
  subtotal: +(order.subtotal_price || 0),
  shipping_cost: +(order.delivery_cost || 0),
  tax_amount: +(order.total_tax || 0),
  discount_amount: +(order.total_discounts || 0),
  total: +(order.total_price || 0),
  currency_code: order.currency_code || 'USD',
  ordered_at: order.created_at,
  shipped_at: order.shipped_at || null,
  cancelled_at: order.cancelled_at || null,
  warehouse_id: warehouseId,
  delivery_method: order.delivery_method?.name || null,
  is_prime: order.is_amazon_prime || false,
  fulfilled_by: order.fulfilled_by_amazon ? 'fba' : 'merchant',
  customer_notes: order.customer_note?.text || null,
  internal_notes: order.notes || null,
  tags: (order.tags || []).map(t => t.name),
  data_source: 'veeqo',
  external_ids: { veeqo: String(order.id) }
};

// ─── Line items ───
const lineItems = (order.line_items || []).map(li => {
  const sku = li.sellable?.sku_code || 'UNKNOWN';
  return {
    sku,
    variant_id: config.variantCache[sku] || null,
    title: li.title || li.sellable?.product_title || '',
    quantity: li.quantity || 1,
    unit_price: +(li.price_per_unit || 0),
    tax_rate: +(li.tax_rate || 0),
    tax_amount: +((li.price_per_unit || 0) * (li.quantity || 1) * (li.tax_rate || 0)).toFixed(2),
    discount_amount: +(li.taxless_discount_per_unit || 0) * (li.quantity || 1),
    cost_price: +(li.sellable?.cost_price || 0) || (config.costPriceCache[sku] || 0),
    remote_line_id: li.remote_id ? String(li.remote_id) : null
  };
});

// ─── Tracking URL builder ───
function buildTrackingUrl(tn, carrierName) {
  if (!tn) return null;
  tn = tn.trim();
  const carrier = (carrierName || '').toLowerCase();
  if (tn.startsWith('1Z') || carrier.includes('ups')) return 'https://www.ups.com/track?track=yes&trackNums=' + tn;
  if (carrier.includes('fedex') || /^\d{12,22}$/.test(tn)) return 'https://www.fedex.com/fedextrack/?trknbr=' + tn;
  if (carrier.includes('usps') || carrier.includes('stamps') || /^9\d{19,33}$/.test(tn)) return 'https://tools.usps.com/go/TrackConfirmAction?tLabels=' + tn;
  if (carrier.includes('ontrac') || /^[CD]\d{10,20}$/.test(tn)) return 'https://www.ontrac.com/tracking/?number=' + tn;
  if (tn.startsWith('TBA')) return 'https://track.amazon.com/tracking/' + tn;
  return 'https://aftership.com/track/' + tn;
}

// ─── Shipment status mapping ───
function mapShipmentStatus(tracking) {
  if (!tracking) return 'created';
  if (tracking.delivered_at) return 'delivered';
  if (tracking.out_for_delivery_at) return 'out_for_delivery';
  if (tracking.in_transit_at) return 'in_transit';
  if (tracking.awaiting_collection_at) return 'awaiting_collection';
  if (tracking.cancelled_at) return 'cancelled';
  if (tracking.returned_to_sender_at) return 'returned_to_sender';
  if (tracking.attempted_delivery_at) return 'attempted_delivery';
  return 'created';
}

// ─── Shipments ───
const shipments = [];
const trackingEvents = [];
for (const alloc of (order.allocations || [])) {
  const ship = alloc.shipment;
  if (!ship) continue;
  const tracking = ship.tracking_number || ship.tracking || ship.trackings?.[0];
  const trackingNumber = tracking?.tracking_number || null;
  const carrierName = ship.carrier?.name || null;
  const carrierCode = ship.carrier?.slug || ship.carrier?.provider_type || null;

  const shipment = {
    _veeqo_id: String(ship.id),
    warehouse_id: warehouseId,
    status: mapShipmentStatus(tracking),
    label_source: carrierCode === 'buy-shipping' ? 'amazon_buy_shipping' : 'veeqo',
    data_source: 'veeqo',
    carrier_name: carrierName,
    carrier_code: carrierCode,
    carrier_service: ship.service_name || ship.short_service_name || ship.carrier_service_name || null,
    service_code: ship.service_type || null,
    tracking_number: trackingNumber,
    tracking_url: buildTrackingUrl(trackingNumber, carrierName),
    label_created_at: ship.created_at || null,
    shipped_at: ship.created_at || ship.shipped_at || null,
    delivered_at: tracking?.delivered_at || null,
    label_cost: ship.outbound_label_charges?.value ?? (ship.cost ? +ship.cost : null),
    insurance_cost: ship.insurance_charges?.value ?? null,
    total_cost: (ship.outbound_label_charges?.value ?? 0) + (ship.insurance_charges?.value ?? 0) || null,
    weight_oz: alloc.total_weight || null,
    is_voided: tracking?.cancelled || false,
    voided_at: tracking?.cancelled_at || null,
    external_ids: { veeqo: String(ship.id) }
  };

  const pkg = alloc.allocation_package;
  if (pkg) {
    shipment.length_in = pkg.depth || null;
    shipment.width_in = pkg.width || null;
    shipment.height_in = pkg.height || null;
    shipment.package_type = pkg.package_name || null;
  }
  shipments.push(shipment);

  // Tracking events from timestamp fields
  if (tracking && trackingNumber) {
    const tsFields = [
      ['created', 'Label created', tracking.created_at],
      ['awaiting_collection', 'Awaiting collection', tracking.awaiting_collection_at],
      ['in_transit', 'In transit', tracking.in_transit_at],
      ['out_for_delivery', 'Out for delivery', tracking.out_for_delivery_at],
      ['delivered', 'Delivered', tracking.delivered_at],
      ['attempted_delivery', 'Delivery attempted', tracking.attempted_delivery_at],
      ['returned_to_sender', 'Returned to sender', tracking.returned_to_sender_at],
      ['cancelled', 'Cancelled', tracking.cancelled_at]
    ];
    for (const [status, desc, ts] of tsFields) {
      if (ts) {
        trackingEvents.push({
          _veeqo_ship_id: String(ship.id),
          tracking_number: trackingNumber,
          status,
          description: desc,
          occurred_at: ts
        });
      }
    }
  }
}

return [{
  json: {
    customer,
    shippingAddress,
    billingAddress,
    order: orderRecord,
    lineItems,
    shipments,
    trackingEvents,
    veeqoId: String(order.id)
  }
}];

// Build the final order payload with all resolved IDs
const t = $('Transform Order').first().json;
const custResult = $('Upsert Customer').all().map(i => i.json).flat();
const addrResult = $('Upsert Addresses').all().map(i => i.json).flat();

// Resolve customer ID
const custArr = Array.isArray(custResult) ? custResult : [custResult];
const customerId = custArr[0]?.id || null;

// Resolve address IDs
const addrArr = Array.isArray(addrResult) ? addrResult : [addrResult];
let shippingAddrId = null;
let billingAddrId = null;
for (const a of addrArr) {
  if (a?.address_type === 'shipping') shippingAddrId = a.id;
  if (a?.address_type === 'billing') billingAddrId = a.id;
}

const order = {
  ...t.order,
  customer_id: customerId,
  shipping_address_id: shippingAddrId,
  billing_address_id: billingAddrId
};

return [{
  json: {
    order,
    lineItems: t.lineItems,
    shipments: t.shipments,
    trackingEvents: t.trackingEvents
  }
}];

// Build line items and shipments with the resolved order_id
const prev = $('Build Order Payload').first().json;
const orderResult = $('Upsert Order').all().map(i => i.json).flat();
const orderArr = Array.isArray(orderResult) ? orderResult : [orderResult];
const orderId = orderArr[0]?.id || null;

const lineItems = prev.lineItems.map(li => ({ ...li, order_id: orderId }));

const shipments = prev.shipments.map(s => {
  const { _veeqo_id, ...rest } = s;
  return { ...rest, order_id: orderId };
});

return [{
  json: {
    orderId,
    lineItems,
    shipments,
    trackingEvents: prev.trackingEvents,
    shipmentsRaw: prev.shipments
  }
}];

// Map tracking events to resolved shipment IDs
const prev = $('Build Related Records').first().json;
const shipResult = $('Upsert Shipments').all().map(i => i.json).flat();
const shipArr = Array.isArray(shipResult) ? shipResult : [shipResult];

// Build mapping: veeqo_id -> supabase shipment_id
const idMap = {};
for (const s of shipArr) {
  if (s?.external_ids?.veeqo) {
    idMap[s.external_ids.veeqo] = s.id;
  }
}

const trackingEvents = (prev.trackingEvents || []).map(te => {
  const { _veeqo_ship_id, ...rest } = te;
  return { ...rest, shipment_id: idMap[_veeqo_ship_id] || null };
}).filter(te => te.shipment_id);

return [{
  json: { trackingEvents }
}];
